import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int val;
        Node left, right;
        Node(int v) { this.val = v; }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String firstLine = br.readLine();
        if (firstLine == null || firstLine.trim().isEmpty()) {
            return; // no input
        }
        StringTokenizer stFirst = new StringTokenizer(firstLine.trim());
        List<Integer> firstNums = new ArrayList<>();
        while (stFirst.hasMoreTokens()) {
            firstNums.add(Integer.parseInt(stFirst.nextToken()));
        }
        StringBuilder sb = new StringBuilder();
        if (firstNums.size() == 2) {
            // Input follows the original statement: single test case without T
            int N = firstNums.get(0);
            int K = firstNums.get(1);
            int ans = processCase(br, N, K);
            sb.append(ans).append('\n');
        } else if (firstNums.size() == 1) {
            // First number is T, number of test cases
            int T = firstNums.get(0);
            for (int t = 0; t < T; t++) {
                // read line containing N and K (skip possible empty lines)
                String line;
                do {
                    line = br.readLine();
                } while (line != null && line.trim().isEmpty());
                if (line == null) break; // safety
                StringTokenizer st = new StringTokenizer(line);
                int N = Integer.parseInt(st.nextToken());
                int K = Integer.parseInt(st.nextToken());
                int ans = processCase(br, N, K);
                sb.append(ans).append('\n');
            }
        } else {
            // Unexpected format; do nothing
            return;
        }
        System.out.print(sb.toString());
    }

    private static int processCase(BufferedReader br, int N, int K) throws IOException {
        Map<Integer, Node> map = new HashMap<>();
        Set<Integer> childSet = new HashSet<>();
        for (int i = 0; i < N - 1; i++) {
            String line;
            // skip possible empty lines
            do {
                line = br.readLine();
            } while (line != null && line.trim().isEmpty());
            if (line == null) break; // safety
            StringTokenizer st = new StringTokenizer(line);
            int p = Integer.parseInt(st.nextToken());
            int c = Integer.parseInt(st.nextToken());
            char dir = st.nextToken().charAt(0);
            Node parent = map.computeIfAbsent(p, Node::new);
            Node child = map.computeIfAbsent(c, Node::new);
            if (dir == 'L')
                parent.left = child;
            else
                parent.right = child;
            childSet.add(c);
        }
        // find root (node that never appears as child)
        Node root = null;
        for (int v : map.keySet()) {
            if (!childSet.contains(v)) {
                root = map.get(v);
                break;
            }
        }
        return kthLargest(root, K);
    }

    private static int kthLargest(Node root, int k) {
        Deque<Node> stack = new ArrayDeque<>();
        Node cur = root;
        int cnt = 0;
        while (!stack.isEmpty() || cur != null) {
            while (cur != null) {
                stack.push(cur);
                cur = cur.right;
            }
            cur = stack.pop();
            cnt++;
            if (cnt == k) return cur.val;
            cur = cur.left;
        }
        return -1; // K is guaranteed to be valid per problem statement
    }
}

